2.query:
fetch logs
| filter isNotNull(order_stage) and isNotNull(stage_duration_ms)
| summarize median(stage_duration_ms), by:{order_stage}

3.query:
fetch logs
| filter isNotNull(order_id) and isNotNull(order_stage)
| summarize last_seen = takeMax(timestamp), by:{order_id, order_stage}
| filter now() - last_seen > 1h
| summarize stalled = count(), by:{order_stage}
